+    fn resolve_frankensearch_model_dir_takes_priority() {
+        let env = mock_env(&[
+            (ENV_MODEL_DIR, "/custom/models"),
+            (ENV_DATA_DIR, "/custom/data"),
+            (ENV_XDG_DATA_HOME, "/xdg"),
+        ]);
+        let root = resolve_cache_root_with(&env);
+        assert_eq!(root, PathBuf::from("/custom/models"));
