+            let metadata = match fs::metadata(&source_path) {
+                Ok(metadata) => metadata,
+                Err(error) if error.kind() == ErrorKind::NotFound => {
+                    stale_files = stale_files.saturating_add(1);
+                    continue;
+                }
+                Err(error) => return Err(error.into()),
+            };
+            let modified_ms = metadata
