+    for (i, demand) in demands.iter().cycle().take(1000).enumerate() {
+        let mode = if i % 2 == 0 {
+            BudgetSchedulerMode::FairShare
+        } else {
+            BudgetSchedulerMode::LatencySensitive
+        };
+        let alloc = scheduler.plan_cycle(*demand, mode);
+
+        assert!(
+            alloc.total() <= policy.total_slots,
