+            alloc.total(),
+            policy.total_slots
+        );
+
+        // Each class allocation should not exceed demand
+        assert!(alloc.ingest <= demand.ingest || demand.ingest == 0);
+        assert!(alloc.embed <= demand.embed || demand.embed == 0);
+        assert!(alloc.query <= demand.query || demand.query == 0);
