+                    row.pending_jobs.to_string(),
+                    row.p95_latency_us.to_string(),
+                    format!("{:.2}", row.burn_ratio),
+                    format!("{:.0}%", row.remaining_ratio * 100.0),
+                    row.backlog_eta_s.to_string(),
